// ✅ GOOD - noun URI, correct verb, correct status codes
[HttpGet("/api/customers/{customerId}/orders")]
public ActionResult<IEnumerable<OrderDto>> GetOrdersByCustomer(int customerId)
{
    var orders = _orderService.GetByCustomer(customerId);
    if (orders == null) return NotFound();
    return Ok(orders);
