// ✅ GOOD - using PATCH to update only the shipping address
[HttpPatch("/api/orders/{id}")]
public IActionResult PatchOrder(int id, JsonPatchDocument<OrderDto> patch)
{
    var order = _orderRepo.GetById(id);
    patch.ApplyTo(order, ModelState);
    if (!ModelState.IsValid) return BadRequest(ModelState);
    _orderRepo.Save(order);
    return NoContent();
}

