// ❌ BAD - no idempotency protection on payment creation, double-charge risk
[HttpPost("/api/payments")]
public async Task<IActionResult> ChargeCustomer(PaymentRequest req)
{
    var result = await _paymentService.Charge(req);
    return Ok(result);
}

// ✅ GOOD - idempotency key prevents double-charge on retry
[HttpPost("/api/payments")]
public async Task<IActionResult> ChargeCustomer(
    PaymentRequest req,
    [FromHeader(Name = "Idempotency-Key")] string idempotencyKey)
{
    if (_cache.TryGetValue(idempotencyKey, out var cached))
        return Ok(cached);
    var result = await _paymentService.Charge(req);
    _cache.Set(idempotencyKey, result, TimeSpan.FromHours(24));
    return Ok(result);
}

